import React, { useState, useEffect } from 'react';

const App = () => {
  const [media, setMedia] = useState([]);
  const [category, setCategory] = useState('');
  const [author, setAuthor] = useState('');
  const [date, setDate] = useState('');
  const [sort, setSort] = useState('title');

  useEffect(() => {
    fetchMedia();
  }, [category, author, date, sort]);

  const fetchMedia = () => {
    // TODO: Implement API call to fetch media data
  };

  const handleCategoryChange = (event) => {
    setCategory(event.target.value);
  };

  const handleAuthorChange = (event) => {
    setAuthor(event.target.value);
  };

  const handleDateChange = (event) => {
    setDate(event.target.value);
  };

  const handleSortChange = (event) => {
    setSort(event.target.value);
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="grid grid-cols-3 gap-4">
        {media.map((item, index) => (
          <div key={index} className="bg-white p-4 rounded shadow-sm">
            <h2 className="text-lg font-bold">{item.title}</h2>
            <p className="text-sm text-gray-600">{item.author}</p>
            <p className="text-sm text-gray-600">{item.date}</p>
          </div>
        ))}
      </div>
      <div className="bg-white p-4 rounded shadow-sm mt-4">
        <h2 className="text-lg font-bold">Filter</h2>
        <div className="flex flex-wrap -mx-4">
          <div className="w-full md:w-1/2 xl:w-1/3 px-4 mb-4">
            <label className="block mb-2 text-gray-600">Category</label>
            <select className="block w-full appearance-none bg-white border border-gray-400 hover:border-gray-500 py-2 px-4 text-base leading-tight focus:outline-none focus:border-gray-500" onChange={handleCategoryChange} value={category}>
              <option value="">All</option>
              <option value="music">Music</option>
              <option value="video">Video</option>
              <option value="image">Image</option>
            </select>
          </div>
          <div className="w-full md:w-1/2 xl:w-1/3 px-4 mb-4">
            <label className="block mb-2 text-gray-600">Author</label>
            <input className="block w-full appearance-none bg-white border border-gray-400 hover:border-gray-500 py-2 px-4 text-base leading-tight focus:outline-none focus:border-gray-500" type="text" value={author} onChange={handleAuthorChange} />
          </div>
          <div className="w-full md:w-1/2 xl:w-1/3 px-4 mb-4">
            <label className="block mb-2 text-gray-600">Date</label>
            <input className="block w-full appearance-none bg-white border border-gray-400 hover:border-gray-500 py-2 px-4 text-base leading-tight focus:outline-none focus:border-gray-500" type="date" value={date} onChange={handleDateChange} />
          </div>
          <div className="w-full md:w-1/2 xl:w-1/3 px-4 mb-4">
            <label className="block mb-2 text-gray-600">Sort</label>
            <select className="block w-full appearance-none bg-white border border-gray-400 hover:border-gray-500 py-2 px-4 text-base leading-tight focus:outline-none focus:border-gray-500" onChange={handleSortChange} value={sort}>
              <option value="title">Title</option>
              <option value="date">Date</option>
              <option value="views">Views</option>
            </select>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;
